// Parse LLM structured JSON response — V2: 8 images + 4 videos = 12 records
const llmResponse = $input.first().json;
const projectRecordId = $('Code — Build LLM Prompt').first().json.projectRecordId;
const brandName = $('Code — Build LLM Prompt').first().json.brandName;

try {
  // Groq/OpenAI format: choices[0].message.content
  const rawText = llmResponse.choices[0].message.content;
  const data = typeof rawText === 'object' ? rawText : JSON.parse(rawText);

  if (!data.images || data.images.length !== 8) {
    throw new Error(`Expected 8 image prompts, got ${data.images ? data.images.length : 0}`);
  }
  if (!data.videos || data.videos.length !== 4) {
    throw new Error(`Expected 4 video prompts, got ${data.videos ? data.videos.length : 0}`);
  }

  const records = [];

  for (const img of data.images) {
    records.push({
      json: {
        projectRecordId,
        phaseNumber: img.phase,
        assetType: 'image',
        phaseLabel: img.label,
        promptLabel: `${brandName} - Phase ${img.phase} (image)`,
        promptText: img.prompt,
        brandName
      }
    });
  }

  for (const vid of data.videos) {
    records.push({
      json: {
        projectRecordId,
        phaseNumber: vid.phase,
        assetType: 'video',
        phaseLabel: vid.label,
        promptLabel: `${brandName} - Phase ${vid.phase} (video)`,
        promptText: vid.prompt,
        brandName
      }
    });
  }

  return records;
} catch (error) {
  return [{
    json: {
      projectRecordId,
      parseError: true,
      errorMessage: `Failed to parse LLM response: ${error.message}`
    }
  }];
}
